import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import logo from '../assets/logo.png';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const styles = {
    nav: {
      background: '#0a3d2e',
      padding: '0 2rem',
      height: '70px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      position: 'sticky',
      top: 0,
      zIndex: 100,
      boxShadow: '0 2px 10px rgba(0,0,0,0.3)',
    },
    links: {
      display: 'flex',
      gap: '1.5rem',
      alignItems: 'center',
    },
    link: {
      color: 'white',
      textDecoration: 'none',
      fontSize: '0.95rem',
    },
    btn: {
      background: '#1ebe74',
      color: 'white',
      border: 'none',
      padding: '8px 18px',
      borderRadius: '8px',
      cursor: 'pointer',
      fontSize: '0.9rem',
    },
    outlineBtn: {
      background: 'transparent',
      color: 'white',
      border: '1px solid white',
      padding: '8px 18px',
      borderRadius: '8px',
      cursor: 'pointer',
      fontSize: '0.9rem',
    },
  };

  return (
    <nav style={styles.nav}>
      <Link to="/" style={{ display: 'flex', alignItems: 'center', textDecoration: 'none' }}>
        <img src={logo} alt="TurfX" style={{ height: '55px', objectFit: 'contain' }} />
      </Link>
      <div style={styles.links}>
        <Link to="/" style={styles.link}>Home</Link>
        <Link to="/explore" style={styles.link}>Explore</Link>
        {user ? (
          <>
            <Link to="/my-bookings" style={styles.link}>My Bookings</Link>
            {user.role === 'owner' && (
              <Link to="/owner" style={styles.link}>Dashboard</Link>
            )}
            <span style={{ color: '#1ebe74', fontSize: '0.9rem' }}>
              Hi, {user.name}
            </span>
            <button
              style={styles.outlineBtn}
              onClick={() => { logout(); navigate('/'); }}
            >
              Logout
            </button>
          </>
        ) : (
          <>
            <Link to="/login" style={styles.link}>Login</Link>
            <button
              style={styles.btn}
              onClick={() => navigate('/register')}
            >
              Sign Up
            </button>
          </>
        )}
      </div>
    </nav>
  );
}
